<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue'; import PageHeader from '@/components/PageHeader.vue'; import StatusTag from '@/components/StatusTag.vue'; import type { ChainRecord } from '@/types'; import { checkIntegrity, getReceipt, getReceipts, refreshReceipt } from '@/api/evidence'; import { useAuthStore } from '@/stores/auth'; import { ElMessage } from 'element-plus'
const auth=useAuthStore(),readOnly=computed(()=>auth.user?.role==='AUDITOR'),loading=ref(false),drawer=ref(false),rows=ref<ChainRecord[]>([]),total=ref(0),current=ref<ChainRecord>();const query=reactive({current:1,size:10,keyword:'',status:'',evidence_type:''});const short=(v?:string)=>v?`${v.slice(0,10)}…${v.slice(-8)}`:'—';const evidenceLabel=(v:string)=>v==='LOCAL_HASH_CHAIN'?'本地哈希链':v==='FISCO_BCOS'?'FISCO BCOS':v
async function load(){loading.value=true;try{const p=await getReceipts(query);rows.value=p.records;total.value=p.total}catch{rows.value=[]}finally{loading.value=false}}function reset(){Object.assign(query,{current:1,size:query.size,keyword:'',status:'',evidence_type:''});load()}async function show(row:ChainRecord){current.value=await getReceipt(row.receipt_id);drawer.value=true}async function refresh(row:ChainRecord){await refreshReceipt(row.receipt_id);ElMessage.success('回执状态已刷新');load()}async function integrity(){const result=await checkIntegrity();ElMessage({type:result.valid?'success':'error',message:result.message})}async function refreshAll(){await load();ElMessage.success('回执列表已刷新')}function copy(v?:string){if(v){navigator.clipboard.writeText(v);ElMessage.success('已复制')}}onMounted(load)
</script>
<template><div><PageHeader title="存证回执" description="查看本地哈希链与FISCO BCOS存证结果"><el-button v-if="!readOnly" @click="integrity">完整性校验</el-button><el-button type="primary" @click="refreshAll">刷新回执状态</el-button></PageHeader><el-alert v-if="readOnly" title="审计员为只读权限" type="info" :closable="false" style="margin-bottom:16px"/><section class="panel"><div class="toolbar"><el-input v-model="query.keyword" placeholder="证书编号或回执编号" clearable style="width:280px"/><el-select v-model="query.evidence_type" placeholder="存证类型" clearable style="width:170px"><el-option label="本地哈希链" value="LOCAL_HASH_CHAIN"/><el-option label="FISCO BCOS" value="FISCO_BCOS"/></el-select><el-select v-model="query.status" placeholder="状态" clearable style="width:140px"><el-option label="已确认" value="CONFIRMED"/><el-option label="待确认" value="PENDING"/><el-option label="失败" value="FAILED"/></el-select><el-button type="primary" @click="query.current=1;load()">查询</el-button><el-button @click="reset">重置</el-button></div><el-table v-loading="loading" :data="rows" empty-text="暂无存证回执"><el-table-column prop="receipt_id" label="回执编号" min-width="170"/><el-table-column prop="certificate_no" label="证书编号" min-width="180"/><el-table-column label="类型" width="120"><template #default="s">{{evidenceLabel(s.row.evidence_type)}}</template></el-table-column><el-table-column label="证书哈希" min-width="170"><template #default="s"><button class="hash-button" @click="copy(s.row.certificate_hash)">{{short(s.row.certificate_hash)}}</button></template></el-table-column><el-table-column prop="block_height" label="区块/链高度"/><el-table-column label="交易哈希" min-width="170"><template #default="s"><button v-if="s.row.tx_hash" class="hash-button" @click="copy(s.row.tx_hash)">{{short(s.row.tx_hash)}}</button><span v-else>本地回执无交易哈希</span></template></el-table-column><el-table-column prop="evidence_time" label="存证时间" min-width="170"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column label="操作" width="150"><template #default="s"><el-button link type="primary" @click="show(s.row)">详情</el-button><el-button v-if="!readOnly" link type="success" @click="refresh(s.row)">刷新</el-button></template></el-table-column></el-table><div class="pagination"><el-pagination v-model:current-page="query.current" v-model:page-size="query.size" :total="total" layout="total, sizes, prev, pager, next" @change="load"/></div></section><el-drawer v-model="drawer" title="存证回执详情" size="580"><div v-if="current" class="receipt"><div class="receipt-ok">✓</div><h3>存证回执有效</h3><p>{{evidenceLabel(current.evidence_type)}}</p><dl><dt>回执编号</dt><dd>{{current.receipt_id}}</dd><dt>证书编号</dt><dd>{{current.certificate_no}}</dd><dt>证书SHA-256</dt><dd class="break">{{current.certificate_hash}}</dd><dt>前序哈希</dt><dd class="break">{{current.previous_hash||'—'}}</dd><dt>当前区块哈希</dt><dd class="break">{{current.current_block_hash||'—'}}</dd><dt>区块高度</dt><dd>{{current.block_height}}</dd><template v-if="current.tx_hash"><dt>交易哈希</dt><dd class="break">{{current.tx_hash}}</dd></template><template v-if="current.contract_address"><dt>合约地址</dt><dd class="break">{{current.contract_address}}</dd></template><template v-if="!current.tx_hash"><dt>交易哈希</dt><dd>本地回执无交易哈希</dd></template><dt>存证时间</dt><dd>{{current.evidence_time}}</dd></dl></div></el-drawer></div></template>